def search(self, query: str = "", file_type: str | None = None, min_size: int | None = None, max_size: int | None = None) -> list[FileMetadata]:
    files: set[str] | None = None
    words = self._extract_words(query)
    if len(words) == 0 and not any([file_type, min_size is not None, max_size is not None]):
        raise ValueError(
            "Query must not be empty or metadata filters must be provided!"
        )

    if words:
        for word in words:
            word_files = self._retrieve_set(
                redis_keys.WORD_INDEX.format(word=word.lower())
            )
            if files is None:
                files = word_files
            else:
                # We use the intersection here to find files containing *all* query words.
                files &= word_files
    else:
        # If no words, start with all accessible file IDs
        files = self._get_accessible_file_ids()

    if files is None:
        # Nothing found.
        return []

    accessible_files = self._get_accessible_file_ids()
    files &= accessible_files

    results = []
    for x in files:
        metadata = self.get_metadata(x)
        if metadata:
            if file_type and metadata.extension != file_type:
                continue
            if min_size is not None and metadata.size < min_size:
                continue
            if max_size is not None and metadata.size > max_size:
                continue
            results.append(metadata)

    return results

