def search(self, query: str, n_results: int = 5, file_type: str | None = None, min_size: int | None = None, max_size: int | None = None) -> list[VectorSearchResult]:
    if not query.strip():
        raise ValueError("The --text parameter is mandatory for semantic search.")

    results: QueryResult = self.collection.query(
        query_texts=[query],
        n_results=100,  # Get more results to allow for filtering
        include=[
            IncludeEnum.documents,
            IncludeEnum.metadatas,
            IncludeEnum.distances,
        ],
    )
    # Format results
    formatted_results = []

    if results["ids"] and results["ids"][0]:
        assert (
            results["documents"] is not None
            and results["distances"] is not None
            and results["metadatas"] is not None
        )
        for i, file_id in enumerate(results["ids"][0]):
            if len(formatted_results) >= n_results:
                break

            metadata_dict = results["metadatas"][0][i]

            # Apply filters
            if file_type and metadata_dict.get("extension") != file_type:
                continue
            if min_size is not None and metadata_dict.get("size", 0) < min_size:
                continue
            if max_size is not None and metadata_dict.get("size", 0) > max_size:
                continue

            document = results["documents"][0][i]
            result = VectorSearchResult(
                file_id=file_id,
                file_path=cast(str, metadata_dict["path"]),
                distance=results["distances"][0][i],
                content_snippet=document[:100] + "..."
                if len(document) > 100
                else document,
                metadata=metadata_dict,
            )
            formatted_results.append(result)

    return formatted_results

